-- Create index
CREATE INDEX idx_employee_dept ON employees(department);
CREATE INDEX idx_emp_salary ON employees(salary);

-- Composite index — order matters!
CREATE INDEX idx_dept_salary ON employees(department, salary);
-- Works for: WHERE department = 'IT'
-- Works for: WHERE department = 'IT' AND salary > 500000
-- Does NOT work for: WHERE salary > 500000 (first column not used)

-- Unique index
CREATE UNIQUE INDEX idx_email ON employees(email);

-- View indexes
SHOW INDEX FROM employees;

-- A — Atomicity: all or nothing
-- C — Consistency: valid state to valid state
-- I — Isolation: concurrent transactions dont interfere
-- D — Durability: committed data survives crashes

-- Transaction example
BEGIN TRANSACTION;
    UPDATE accounts SET balance = balance - 5000 WHERE id = 1;
    UPDATE accounts SET balance = balance + 5000 WHERE id = 2;
COMMIT;
-- If any fails, ROLLBACK undoes both

-- SAVEPOINT — partial rollback
BEGIN;
    INSERT INTO orders VALUES (1, 'Book', 500);
    SAVEPOINT order_created;
    INSERT INTO shipping VALUES (1, 'Delhi');
    -- Oops, wrong address
    ROLLBACK TO order_created;
    INSERT INTO shipping VALUES (1, 'Mumbai');
COMMIT;

-- INSERT
INSERT INTO employees (name, salary, dept)
VALUES ('Alice', 800000, 'IT');

-- Insert multiple
INSERT INTO employees (name, salary, dept) VALUES
    ('Bob', 900000, 'IT'),
    ('Charlie', 700000, 'HR'),
    ('Diana', 1000000, 'IT');

-- Insert from SELECT
INSERT INTO high_earners (name, salary)
SELECT name, salary FROM employees WHERE salary > 1000000;

-- UPDATE with WHERE (always!)
UPDATE employees SET salary = salary * 1.1 WHERE department = 'IT';
-- WITHOUT WHERE updates ALL rows! Disaster!

-- DELETE with WHERE
DELETE FROM employees WHERE id = 5;
-- TRUNCATE removes all rows (faster, no log)
TRUNCATE TABLE temp_data;

-- CREATE TABLE
CREATE TABLE employees (
    id INT PRIMARY KEY AUTO_INCREMENT,
    name VARCHAR(100) NOT NULL,
    email VARCHAR(255) UNIQUE,
    salary DECIMAL(10,2) DEFAULT 0,
    dept_id INT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (dept_id) REFERENCES departments(id)
);

-- ALTER TABLE
ALTER TABLE employees ADD COLUMN phone VARCHAR(15);
ALTER TABLE employees DROP COLUMN phone;
ALTER TABLE employees MODIFY COLUMN name VARCHAR(200);

-- DROP — deletes entire table (irreversible!)
DROP TABLE IF EXISTS temp_data;
